 12ŌåÆ
 13ŌåÆconst (
 14ŌåÆ	// DefaultRegistryURL is the official MCP Registry API endpoint.
 15ŌåÆ	DefaultRegistryURL = "https://registry.modelcontextprotocol.io"
 16ŌåÆ
 17ŌåÆ	// DefaultCacheTTL is how long the server list is cached.
 18ŌåÆ	DefaultCacheTTL = 15 * time.Minute
