 20ŌåÆ
 21ŌåÆ// Client fetches and caches MCP server metadata from the official registry.
 22ŌåÆtype Client struct {
 23ŌåÆ	baseURL    string
 24ŌåÆ	httpClient *http.Client
 25ŌåÆ	cacheTTL   time.Duration
 26ŌåÆ
 27ŌåÆ	mu        sync.RWMutex
 28ŌåÆ	cached    []RegistryServer
 29ŌåÆ	cachedAt  time.Time
 30ŌåÆ}
 31ŌåÆ
 32ŌåÆ// NewClient creates a registry client with sensible defaults.
 33ŌåÆfunc NewClient(httpClient *http.Client) *Client {
 34ŌåÆ	if httpClient == nil {
 35ŌåÆ		httpClient = &http.Client{Timeout: 30 * time.Second}
 36ŌåÆ	}
 37ŌåÆ	return &Client{
 38ŌåÆ		baseURL:    DefaultRegistryURL,
 39ŌåÆ		httpClient: httpClient,
 40ŌåÆ		cacheTTL:   DefaultCacheTTL,
 41ŌåÆ	}
 42ŌåÆ}
 43ŌåÆ
 44ŌåÆ// WithBaseURL overrides the registry URL (useful for testing).
 45ŌåÆfunc (c *Client) WithBaseURL(url string) *Client {
 46ŌåÆ	c.baseURL = url
