 48ŌåÆ}
 49ŌåÆ
 50ŌåÆ// FetchAll returns every server from the registry, using the cache if fresh.
 51ŌåÆfunc (c *Client) FetchAll(ctx context.Context) ([]RegistryServer, error) {
 52ŌåÆ	c.mu.RLock()
 53ŌåÆ	if c.cached != nil && time.Since(c.cachedAt) < c.cacheTTL {
 54ŌåÆ		result := make([]RegistryServer, len(c.cached))
 55ŌåÆ		copy(result, c.cached)
 56ŌåÆ		c.mu.RUnlock()
 57ŌåÆ		return result, nil
 58ŌåÆ	}
 59ŌåÆ	c.mu.RUnlock()
 60ŌåÆ
 61ŌåÆ	servers, err := c.fetchFromRegistry(ctx)
 62ŌåÆ	if err != nil {
 63ŌåÆ		return nil, err
 64ŌåÆ	}
 65ŌåÆ
 66ŌåÆ	c.mu.Lock()
 67ŌåÆ	c.cached = servers
 68ŌåÆ	c.cachedAt = time.Now()
 69ŌåÆ	c.mu.Unlock()
 70ŌåÆ
 71ŌåÆ	result := make([]RegistryServer, len(servers))
 72ŌåÆ	copy(result, servers)
 73ŌåÆ	return result, nil
 74ŌåÆ}
