 76ŌåÆ// Search filters servers by a case-insensitive substring match on name or description.
 77ŌåÆfunc (c *Client) Search(ctx context.Context, query string) ([]RegistryServer, error) {
 78ŌåÆ	all, err := c.FetchAll(ctx)
 79ŌåÆ	if err != nil {
 80ŌåÆ		return nil, err
 81ŌåÆ	}
 82ŌåÆ	if query == "" {
 83ŌåÆ		return all, nil
 84ŌåÆ	}
 85ŌåÆ
 86ŌåÆ	q := strings.ToLower(query)
 87ŌåÆ	var matches []RegistryServer
 88ŌåÆ	for _, srv := range all {
 89ŌåÆ		if strings.Contains(strings.ToLower(srv.Name), q) ||
 90ŌåÆ			strings.Contains(strings.ToLower(srv.Description), q) {
 91ŌåÆ			matches = append(matches, srv)
 92ŌåÆ		}
 93ŌåÆ	}
 94ŌåÆ	return matches, nil
 95ŌåÆ}
 96ŌåÆ
 97ŌåÆ// Get returns a single server by registry ID (name).
 98ŌåÆfunc (c *Client) Get(ctx context.Context, registryID string) (*RegistryServer, error) {
 99ŌåÆ	all, err := c.FetchAll(ctx)
100ŌåÆ	if err != nil {
101ŌåÆ		return nil, err
102ŌåÆ	}
103ŌåÆ	for _, srv := range all {
104ŌåÆ		if srv.Name == registryID {
105ŌåÆ			return &srv, nil
106ŌåÆ		}
107ŌåÆ	}
108ŌåÆ	return nil, nil
109ŌåÆ}
