111ŌåÆfunc (c *Client) fetchFromRegistry(ctx context.Context) ([]RegistryServer, error) {
112ŌåÆ	url := c.baseURL + "/v0/servers"
113ŌåÆ	req, err := http.NewRequestWithContext(ctx, http.MethodGet, url, nil)
114ŌåÆ	if err != nil {
115ŌåÆ		return nil, fmt.Errorf("registry: create request: %w", err)
116ŌåÆ	}
117ŌåÆ	req.Header.Set("Accept", "application/json")
118ŌåÆ
119ŌåÆ	resp, err := c.httpClient.Do(req)
120ŌåÆ	if err != nil {
121ŌåÆ		return nil, fmt.Errorf("registry: fetch: %w", err)
122ŌåÆ	}
