  3ŌåÆimport (
  4ŌåÆ	"context"
  5ŌåÆ	"encoding/json"
  6ŌåÆ	"fmt"
  7ŌåÆ	"net/http"
  8ŌåÆ	"net/url"
  9ŌåÆ	"strings"
 10ŌåÆ	"sync"
 11ŌåÆ	"time"
 12ŌåÆ)
 13ŌåÆ
 14ŌåÆconst (
 15ŌåÆ	// DefaultRegistryURL is the official MCP Registry API endpoint.
 16ŌåÆ	DefaultRegistryURL = "https://registry.modelcontextprotocol.io"
 17ŌåÆ
 18ŌåÆ	// DefaultCacheTTL is how long the server list is cached.
 19ŌåÆ	DefaultCacheTTL = 15 * time.Minute
 20ŌåÆ)
 21ŌåÆ
 22ŌåÆ// Client fetches and caches MCP server metadata from the official registry.
 23ŌåÆtype Client struct {
 24ŌåÆ	baseURL    string
 25ŌåÆ	httpClient *http.Client
 26ŌåÆ	cacheTTL   time.Duration
 27ŌåÆ
 28ŌåÆ	mu        sync.RWMutex
 29ŌåÆ	cached    []RegistryServer
 30ŌåÆ	cachedAt  time.Time
 31ŌåÆ}
 32ŌåÆ
 33ŌåÆ// NewClient creates a registry client with sensible defaults.
 34ŌåÆfunc NewClient(httpClient *http.Client) *Client {
 35ŌåÆ	if httpClient == nil {
 36ŌåÆ		httpClient = &http.Client{Timeout: 30 * time.Second}
 37ŌåÆ	}
 38ŌåÆ	return &Client{
 39ŌåÆ		baseURL:    DefaultRegistryURL,
 40ŌåÆ		httpClient: httpClient,
 41ŌåÆ		cacheTTL:   DefaultCacheTTL,
 42ŌåÆ	}
 43ŌåÆ}
 44ŌåÆ
 45ŌåÆ// WithBaseURL overrides the registry URL (useful for testing).
 46ŌåÆfunc (c *Client) WithBaseURL(url string) *Client {
 47ŌåÆ	c.baseURL = url
 48ŌåÆ	return c
 49ŌåÆ}
 50ŌåÆ
 51ŌåÆ// FetchAll returns every server from the registry, using the cache if fresh.
 52ŌåÆfunc (c *Client) FetchAll(ctx context.Context) ([]RegistryServer, error) {
 53ŌåÆ	c.mu.RLock()
 54ŌåÆ	if c.cached != nil && time.Since(c.cachedAt) < c.cacheTTL {
 55ŌåÆ		result := make([]RegistryServer, len(c.cached))
 56ŌåÆ		copy(result, c.cached)
 57ŌåÆ		c.mu.RUnlock()
 58ŌåÆ		return result, nil
 59ŌåÆ	}
 60ŌåÆ	c.mu.RUnlock()
 61ŌåÆ
 62ŌåÆ	servers, err := c.fetchFromRegistry(ctx)
 63ŌåÆ	if err != nil {
 64ŌåÆ		return nil, err
 65ŌåÆ	}
 66ŌåÆ
 67ŌåÆ	c.mu.Lock()
 68ŌåÆ	c.cached = servers
 69ŌåÆ	c.cachedAt = time.Now()
 70ŌåÆ	c.mu.Unlock()
 71ŌåÆ
 72ŌåÆ	result := make([]RegistryServer, len(servers))
 73ŌåÆ	copy(result, servers)
 74ŌåÆ	return result, nil
 75ŌåÆ}
 76ŌåÆ
 77ŌåÆ// Search filters servers by a case-insensitive substring match on name or description.
 78ŌåÆfunc (c *Client) Search(ctx context.Context, query string) ([]RegistryServer, error) {
 79ŌåÆ	all, err := c.FetchAll(ctx)
 80ŌåÆ	if err != nil {
 81ŌåÆ		return nil, err
 82ŌåÆ	}
 83ŌåÆ	if query == "" {
 84ŌåÆ		return all, nil
 85ŌåÆ	}
 86ŌåÆ
 87ŌåÆ	q := strings.ToLower(query)
 88ŌåÆ	var matches []RegistryServer
 89ŌåÆ	for _, srv := range all {
 90ŌåÆ		if strings.Contains(strings.ToLower(srv.Name), q) ||
 91ŌåÆ			strings.Contains(strings.ToLower(srv.Description), q) {
 92ŌåÆ			matches = append(matches, srv)
 93ŌåÆ		}
 94ŌåÆ	}
 95ŌåÆ	return matches, nil
 96ŌåÆ}
 97ŌåÆ
 98ŌåÆ// Get returns a single server by registry ID (name).
 99ŌåÆfunc (c *Client) Get(ctx context.Context, registryID string) (*RegistryServer, error) {
100ŌåÆ	all, err := c.FetchAll(ctx)
101ŌåÆ	if err != nil {
102ŌåÆ		return nil, err
103ŌåÆ	}
104ŌåÆ	for _, srv := range all {
105ŌåÆ		if srv.Name == registryID {
106ŌåÆ			return &srv, nil
107ŌåÆ		}
108ŌåÆ	}
109ŌåÆ	return nil, nil
110ŌåÆ}
111ŌåÆ
112ŌåÆ// pageSize is the maximum number of servers per page (registry max is 100).
113ŌåÆconst pageSize = 100
114ŌåÆ
115ŌåÆfunc (c *Client) fetchFromRegistry(ctx context.Context) ([]RegistryServer, error) {
116ŌåÆ	var all []RegistryServer
117ŌåÆ	var cursor string
118ŌåÆ
119ŌåÆ	for {
120ŌåÆ		page, nextCursor, err := c.fetchPage(ctx, cursor)
121ŌåÆ		if err != nil {
122ŌåÆ			return nil, err
123ŌåÆ		}
124ŌåÆ		all = append(all, page...)
125ŌåÆ		if nextCursor == "" || len(page) == 0 {
126ŌåÆ			break
127ŌåÆ		}
128ŌåÆ		cursor = nextCursor
129ŌåÆ	}
130ŌåÆ	return all, nil
131ŌåÆ}
132ŌåÆ
133ŌåÆfunc (c *Client) fetchPage(ctx context.Context, cursor string) ([]RegistryServer, string, error) {
134ŌåÆ	u := c.baseURL + "/v0/servers?limit=" + fmt.Sprintf("%d", pageSize)
135ŌåÆ	if cursor != "" {
136ŌåÆ		u += "&cursor=" + url.QueryEscape(cursor)
137ŌåÆ	}
138ŌåÆ
139ŌåÆ	req, err := http.NewRequestWithContext(ctx, http.MethodGet, u, nil)
140ŌåÆ	if err != nil {
141ŌåÆ		return nil, "", fmt.Errorf("registry: create request: %w", err)
142ŌåÆ	}
143ŌåÆ	req.Header.Set("Accept", "application/json")
144ŌåÆ
145ŌåÆ	resp, err := c.httpClient.Do(req)
146ŌåÆ	if err != nil {
147ŌåÆ		return nil, "", fmt.Errorf("registry: fetch: %w", err)
148ŌåÆ	}
149ŌåÆ	defer resp.Body.Close()
150ŌåÆ
151ŌåÆ	if resp.StatusCode != http.StatusOK {
152ŌåÆ		return nil, "", fmt.Errorf("registry: unexpected status %d", resp.StatusCode)
153ŌåÆ	}
154ŌåÆ
155ŌåÆ	var result RegistryResponse
156ŌåÆ	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
157ŌåÆ		return nil, "", fmt.Errorf("registry: decode: %w", err)
158ŌåÆ	}
159ŌåÆ
160ŌåÆ	servers := make([]RegistryServer, len(result.Servers))
161ŌåÆ	for i, entry := range result.Servers {
162ŌåÆ		servers[i] = entry.Server
163ŌåÆ	}
164ŌåÆ
165ŌåÆ	var nextCursor string
166ŌåÆ	if result.Metadata != nil {
167ŌåÆ		nextCursor = result.Metadata.NextCursor
168ŌåÆ	}
169ŌåÆ	return servers, nextCursor, nil
170ŌåÆ}
